import hashlib
import secrets

def hash_file(file_path):
    with open(file_path, 'rb') as file:
        file_hash = hashlib.sha256()
        while chunk := file.read(4096):
            file_hash.update(chunk)
    
    return file_hash.hexdigest()

def secure_hash_file(file_path, key=None):
    if key is None:
        key = secrets.token_bytes(32)  # Generate a random key
    else:
        key = bytes(key, 'utf-8')  # Convert key to bytes
    
    with open(file_path, 'rb') as file:
        encrypted_data = secrets.token_urlsafe(16).encode() + key + file.read()
    
    return hashlib.sha256(encrypted_data).hexdigest(), key.hex()

# Usage
file_hash = hash_file('path_to_your_file.txt')
print(f"File Hash: {file_hash}")

secure_hash, secure_key = secure_hash_file('path_to_your_file.txt')
print(f"Secure File Hash: {secure_hash}")
print(f"Secure Key: {secure_key}")